import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, getDocs } from 'firebase/firestore';

function TeamLineup() {
  const { teamId } = useParams();
  const navigate = useNavigate();
  const [teamData, setTeamData] = useState(null);
  const [players, setPlayers] = useState([]);
  const [lineup, setLineup] = useState([]);
  const [pinVerified, setPinVerified] = useState(false);

  useEffect(() => {
    const fetchTeamData = async () => {
      const teamRef = doc(db, 'teams', teamId);
      const teamSnap = await getDoc(teamRef);
      if (teamSnap.exists()) {
        setTeamData(teamSnap.data());
        setLineup(Array(teamSnap.data().playerCount).fill(null));  // Initialize empty lineup slots
      } else {
        alert('Team not found');
        navigate('/teams-management');
      }
    };

    const fetchPlayers = async () => {
      const playersCollection = await getDocs(collection(db, 'players'));
      const playersData = playersCollection.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
      }));
      setPlayers(playersData);
    };

    fetchTeamData();
    fetchPlayers();
  }, [teamId, navigate]);

  const verifyPin = () => {
    const userPin = prompt("Enter PIN to view lineup:");
    if (userPin === teamData.pin) {
      setPinVerified(true);
    } else {
      alert("Incorrect PIN. Access denied.");
      navigate('/teams-management');
    }
  };

  const handleSelectPlayer = (index) => {
    const playerOptions = players.map(player => `${player.firstName} ${player.lastName}`).join('\n');
    const selectedName = prompt(`Select a player:\n${playerOptions}`);
    const selectedPlayer = players.find(
      (player) => `${player.firstName} ${player.lastName}` === selectedName
    );

    if (selectedPlayer) {
      const updatedLineup = [...lineup];
      updatedLineup[index] = selectedPlayer;
      setLineup(updatedLineup);
    }
  };

  if (!teamData) return <p>Loading...</p>;
  if (!pinVerified) {
    verifyPin();
    return null;
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Team Lineup - {teamData.name}</h1>

      <img
        src={`${process.env.PUBLIC_URL}/images/Tactics/${teamData.playerCount}_players_${teamData.tactic}.png`}
        alt="Tactic"
        style={styles.tacticImage}
      />

      <div style={styles.lineupContainer}>
        {lineup.map((player, index) => (
          <div
            key={index}
            style={styles.playerBox}
            onClick={() => handleSelectPlayer(index)}
          >
            {player ? (
              <>
                <img
                  src={player.profilePicture ? player.profilePicture : `${process.env.PUBLIC_URL}/images/profile_picture.jpg`}
                  alt={player.firstName}
                  style={styles.playerImage}
                />
                <p style={styles.playerName}>
                  {player.lastName}, {player.firstName}
                </p>
                <p style={styles.playerPosition}>{player.favoritePosition}</p>
                <p style={styles.playerPower}>Power: {player.powerRating}</p>
              </>
            ) : (
              <p style={styles.emptySlot}>+ Slot {index + 1}</p>
            )}
          </div>
        ))}
      </div>

      <button style={styles.backButton} onClick={() => navigate('/teams-management')}>
        Back to Teams Management
      </button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  title: {
    fontSize: '24px',
    marginBottom: '20px',
    color: '#293F14',
  },
  tacticImage: {
    width: '60%',
    height: 'auto',
    marginBottom: '30px',
    borderRadius: '10px',
  },
  lineupContainer: {
    display: 'flex',
    justifyContent: 'center',
    gap: '20px',
    flexWrap: 'wrap',
    width: '80%',
  },
  playerBox: {
    width: '120px',
    height: '160px',
    backgroundColor: '#7FC6A4',
    borderRadius: '10px',
    border: '2px solid #5D737E',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'pointer',
    boxShadow: '3px 3px #386C0B',
    padding: '10px',
  },
  playerImage: {
    width: '60px',
    height: '60px',
    borderRadius: '50%',
    marginBottom: '5px',
  },
  playerName: {
    fontSize: '12px',
    fontWeight: 'bold',
    textAlign: 'center',
  },
  playerPosition: {
    fontSize: '10px',
    color: '#293F14',
  },
  playerPower: {
    fontSize: '10px',
    textDecoration: 'underline',
  },
  emptySlot: {
    fontSize: '14px',
    color: '#293F14',
  },
  backButton: {
    marginTop: '20px',
    backgroundColor: '#5D737E',
    color: '#FFFFFF',
    padding: '10px 20px',
    borderRadius: '8px',
    border: '2px solid #293F14',
    cursor: 'pointer',
  },
};

export default TeamLineup;
